                //   "guest" = ich bin zu einem Host gejoint, Welt ist eine Kopie
                // Bei "host" und "guest" startet Multi-User-Sync automatisch
                // beim Init (statt manueller Toggle-Klick).
                role: "solo",
                // Ring 11.5: bei "guest" — wohin verbinden wir uns initial?
